namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics including statistics and analysis." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Literature, writing, and linguistic studies." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Exploration of past events, civilizations, and cultural developments." }
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor of Computer Science", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 papers in top-tier conferences and holds three patents in neural network optimization.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. Michael Torres", Title = "Associate Professor of Mathematics", Bio = "Dr. Torres focuses on applied mathematics and numerical analysis. He previously worked at NASA's Jet Propulsion Laboratory on trajectory optimization.", Email = "m.torres@university.edu" },
            new() { Id = 3, Name = "Prof. Emily Watson", Title = "Professor of English", Bio = "Prof. Watson is a published novelist and literary critic specializing in contemporary American fiction and creative writing pedagogy.", Email = "e.watson@university.edu" },
            new() { Id = 4, Name = "Dr. James Park", Title = "Associate Professor of Physics", Bio = "Dr. Park researches quantum computing and condensed matter physics. He leads the university's Quantum Information Lab.", Email = "j.park@university.edu" },
            new() { Id = 5, Name = "Dr. Lisa Rodriguez", Title = "Professor of History", Bio = "Dr. Rodriguez is an expert in Latin American history and post-colonial studies with fieldwork experience across Central and South America.", Email = "l.rodriguez@university.edu" },
            new() { Id = 6, Name = "Dr. Alan Wright", Title = "Senior Lecturer in Computer Science", Bio = "Dr. Wright brings 15 years of industry experience in software engineering. He specializes in distributed systems and cloud architecture.", Email = "a.wright@university.edu" }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control structures, functions, and basic data structures. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, InstructorId = 1, IsFeatured = true },
            new() { Id = 2, Code = "CS201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide and conquer, dynamic programming, greedy algorithms).", Credits = 4, Schedule = "Tue/Thu 10:00–11:50 AM", DepartmentId = 1, InstructorId = 1 },
            new() { Id = 3, Code = "CS301", Title = "Distributed Systems", Description = "Principles of distributed computing including consensus algorithms, replication, fault tolerance, and scalable architectures for modern cloud platforms.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = 1, InstructorId = 6, IsFeatured = true },
            new() { Id = 4, Code = "MATH101", Title = "Calculus I", Description = "Introduction to differential calculus covering limits, derivatives, and applications. Includes optimization problems and related rates.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 2, InstructorId = 2 },
            new() { Id = 5, Code = "MATH201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to data science and engineering.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, InstructorId = 2, IsFeatured = true },
            new() { Id = 6, Code = "ENG101", Title = "Academic Writing", Description = "Develop essential writing skills for university-level work. Focus on argumentation, research methods, citation practices, and revision strategies.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 3, InstructorId = 3 },
            new() { Id = 7, Code = "ENG205", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present day, exploring themes of identity, freedom, and the American experience.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", DepartmentId = 3, InstructorId = 3 },
            new() { Id = 8, Code = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Covers Newton's laws, energy conservation, rotational dynamics, and oscillatory motion with laboratory component.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Lab Thu 2:00–4:00 PM", DepartmentId = 4, InstructorId = 4, IsFeatured = true },
            new() { Id = 9, Code = "PHYS301", Title = "Quantum Mechanics", Description = "Introduction to quantum theory including wave functions, the Schrödinger equation, angular momentum, and applications to atomic and molecular systems.", Credits = 3, Schedule = "Tue/Thu 10:00–11:20 AM", DepartmentId = 4, InstructorId = 4 },
            new() { Id = 10, Code = "HIST101", Title = "World Civilizations", Description = "A broad survey of major world civilizations from antiquity to the modern era, examining political, economic, social, and cultural developments.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", DepartmentId = 5, InstructorId = 5 },
            new() { Id = 11, Code = "HIST250", Title = "Latin American History", Description = "Exploration of Latin American societies from pre-Columbian civilizations through independence movements to contemporary challenges.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 5, InstructorId = 5, IsFeatured = true },
            new() { Id = 12, Code = "CS401", Title = "Machine Learning", Description = "Theory and practice of machine learning including supervised and unsupervised methods, neural networks, and model evaluation techniques.", Credits = 3, Schedule = "Tue/Thu 3:30–4:50 PM", DepartmentId = 1, InstructorId = 1, IsFeatured = true }
        };
    }

    public List<Department> GetAllDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public Instructor? GetInstructor(int id) => _instructors.FirstOrDefault(i => i.Id == id);

    public Department? GetDepartmentForCourse(int courseId)
    {
        var course = GetCourse(courseId);
        return course != null ? GetDepartment(course.DepartmentId) : null;
    }
}

