            new() { Id = 8, Code = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Covers Newton's laws, energy conservation, rotational dynamics, and oscillatory motion with laboratory component.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Lab Thu 2:00–4:00 PM", DepartmentId = 4, InstructorId = 4, IsFeatured = true },
            new() { Id = 9, Code = "PHYS301", Title = "Quantum Mechanics", Description = "Introduction to quantum theory including wave functions, the Schrödinger equation, angular momentum, and applications to atomic and molecular systems.", Credits = 3, Schedule = "Tue/Thu 10:00–11:20 AM", DepartmentId = 4, InstructorId = 4 },
            new() { Id = 10, Code = "HIST101", Title = "World Civilizations", Description = "A broad survey of major world civilizations from antiquity to the modern era, examining political, economic, social, and cultural developments.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", DepartmentId = 5, InstructorId = 5 },
            new() { Id = 11, Code = "HIST250", Title = "Latin American History", Description = "Exploration of Latin American societies from pre-Columbian civilizations through independence movements to contemporary challenges.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 5, InstructorId = 5, IsFeatured = true },
            new() { Id = 12, Code = "CS401", Title = "Machine Learning", Description = "Theory and practice of machine learning including supervised and unsupervised methods, neural networks, and model evaluation techniques.", Credits = 3, Schedule = "Tue/Thu 3:30–4:50 PM", DepartmentId = 1, InstructorId = 1, IsFeatured = true }
        };
    }

    public List<Department> GetAllDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public Instructor? GetInstructor(int id) => _instructors.FirstOrDefault(i => i.Id == id);

    public Department? GetDepartmentForCourse(int courseId)
    {
        var course = GetCourse(courseId);
        return course != null ? GetDepartment(course.DepartmentId) : null;
    }
}

