arguments.file_text:
@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<div class="container">
    <div class="text-center my-4">
        <h1>University Course Catalog</h1>
        <p class="lead text-muted">Explore departments, discover courses, and enroll for the upcoming semester.</p>
    </div>

    <section class="mb-5">
        <h2>Featured Courses</h2>
        <div class="row">
            @foreach (var course in featuredCourses)
            {
                var dept = Catalog.GetDepartment(course.DepartmentId);
                <div class="col-md-4 mb-3">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@course.Code — @course.Title</h5>
                            <p class="card-text text-muted">@dept?.Name · @course.Credits credits</p>
                            <p class="card-text">@Truncate(course.Description, 100)</p>
                        </div>
                        <div class="card-footer">
                            <a href="/courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    </section>

    <section class="mb-5">
        <h2>Departments</h2>
        <div class="row">
            @foreach (var dept in departments)
            {
                <div class="col-md-4 mb-3">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@dept.Name</h5>
                            <p class="card-text">@dept.Description</p>
                        </div>
                        <div class="card-footer">
                            <a href="/courses?departmentId=@dept.Id" class="btn btn-outline-secondary btn-sm">Browse Courses</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    </section>

    <section class="text-center mb-5">
        <a href="/courses" class="btn btn-lg btn-primary me-2">Browse All Courses</a>
        <a href="/enroll" class="btn btn-lg btn-outline-success">Enroll Now</a>
    </section>
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetAllDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog
@rendermode InteractiveServer

<PageTitle>Courses — University Course Catalog</PageTitle>

<div class="container">
    <h1 class="my-4">Course Catalog</h1>

    <div class="row mb-4">
        <div class="col-md-6">
            <input type="text" class="form-control" placeholder="Search courses..."
                   @bind="searchTerm" @bind:event="oninput" />
        </div>
        <div class="col-md-4">
            <select class="form-select" @bind="selectedDepartmentId">
                <option value="0">All Departments</option>
                @foreach (var dept in departments)
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            </select>
        </div>
        <div class="col-md-2">
            <button class="btn btn-secondary w-100" @onclick="ClearFilters">Clear</button>
        </div>
    </div>

    @if (filteredCourses.Count == 0)
    {
        <div class="alert alert-info">No courses found matching your criteria.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th>Code</th>
                        <th>Title</th>
                        <th>Department</th>
                        <th>Credits</th>
                        <th>Schedule</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var course in filteredCourses)
                    {
                        var dept = Catalog.GetDepartment(course.DepartmentId);
                        <tr>
                            <td><strong>@course.Code</strong></td>
                            <td>@course.Title</td>
                            <td>@dept?.Name</td>
                            <td>@course.Credits</td>
                            <td>@course.Schedule</td>
                            <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
        <p class="text-muted">Showing @filteredCourses.Count course(s)</p>
    }
</div>

@code {
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Department> departments = new();
    private List<Course> filteredCourses = new();

    private string _searchTerm = string.Empty;
    private string searchTerm
    {
        get => _searchTerm;
        set { _searchTerm = value; ApplyFilters(); }
    }

    private int _selectedDepartmentId;
    private int selectedDepartmentId
    {
        get => _selectedDepartmentId;
        set { _selectedDepartmentId = value; ApplyFilters(); }
    }

    protected override void OnInitialized()
    {
        departments = Catalog.GetAllDepartments();
        if (DepartmentId.HasValue)
            _selectedDepartmentId = DepartmentId.Value;
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        filteredCourses = Catalog.SearchCourses(
            string.IsNullOrWhiteSpace(searchTerm) ? null : searchTerm,
            selectedDepartmentId > 0 ? selectedDepartmentId : null);
    }

    private void ClearFilters()
    {
        _searchTerm = string.Empty;
        _selectedDepartmentId = 0;
        ApplyFilters();
    }
}

