@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enroll — University Course Catalog</PageTitle>

<div class="container">
    <h1 class="my-4">Enrollment Request</h1>

    @if (submitted)
    {
        <div class="alert alert-success">
            <h4>Enrollment Request Submitted!</h4>
            <p>Thank you, <strong>@model.StudentName</strong>. Your enrollment request for
               <strong>@selectedCourseTitle</strong> has been received. You will receive a
               confirmation via your university email.</p>
        </div>
        <a href="/enroll" class="btn btn-primary">Submit Another Request</a>
        <a href="/courses" class="btn btn-outline-secondary ms-2">Browse Courses</a>
    }
    else
    {
        <p class="text-muted mb-4">Fill out the form below to request enrollment in a course. All fields are required.</p>

        <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger mb-3" />

            <div class="mb-3">
                <label for="studentName" class="form-label">Full Name</label>
                <InputText id="studentName" class="form-control" @bind-Value="model.StudentName" />
                <ValidationMessage For="() => model.StudentName" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="studentId" class="form-label">Student ID</label>
                <InputText id="studentId" class="form-control" @bind-Value="model.StudentId"
                           placeholder="e.g., CS123456" />
                <ValidationMessage For="() => model.StudentId" class="text-danger" />
                <div class="form-text">Format: 2 uppercase letters followed by 6 digits.</div>
            </div>

            <div class="mb-3">
                <label for="courseId" class="form-label">Course</label>
                <InputSelect id="courseId" class="form-select" @bind-Value="model.CourseId">
                    <option value="0">— Select a course —</option>
                    @foreach (var course in courses)
                    {
                        <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr)</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.CourseId" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
            <a href="/courses" class="btn btn-outline-secondary ms-2">Cancel</a>
        </EditForm>
    }
</div>

@code {
    [SupplyParameterFromForm] private EnrollmentRequest model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;
    private string selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        courses = Catalog.GetAllCourses();
        if (CourseId.HasValue && model.CourseId == 0)
            model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        var course = Catalog.GetCourse(model.CourseId);
        selectedCourseTitle = course != null ? $"{course.Code} — {course.Title}" : "Unknown Course";
        submitted = true;
    }
}

